// Tiny Express server with a deliberately small API surface.
const crypto = require('crypto');
const express = require('express');
const fs = require('fs');
const path = require('path');

const app = express();
app.use(
  express.json({
    verify: (req, _res, body) => {
      req.rawBody = Buffer.from(body);
    },
  }),
);

const items = [
  { id: 1, name: 'alpha', qty: 3 },
  { id: 2, name: 'beta', qty: 5 },
];
const webhookSecret = fs
  .readFileSync(path.join(__dirname, '../data/webhook-secret.txt'), 'utf8')
  .replace(/\r?\n$/, '');
const acceptedEventIds = new Set();

function isValidWebhookEvent(body) {
  return (
    body &&
    !Array.isArray(body) &&
    typeof body.id === 'string' &&
    body.id.length > 0 &&
    typeof body.type === 'string' &&
    body.type.length > 0 &&
    typeof body.timestamp === 'number' &&
    body.data &&
    !Array.isArray(body.data) &&
    typeof body.data === 'object'
  );
}

app.get('/health', (_req, res) => {
  res.json({ status: 'ok' });
});

app.get('/items', (_req, res) => {
  res.json({ items });
});

app.get('/items/:id', (req, res) => {
  const id = Number(req.params.id);
  const item = items.find((it) => it.id === id);
  if (!item) {
    res.status(404).json({ error: 'not_found', id });
    return;
  }
  res.json({ item });
});

app.post('/webhook', (req, res) => {
  const expectedSignature = Buffer.from(
    crypto
      .createHmac('sha256', webhookSecret)
      .update(req.rawBody || Buffer.alloc(0))
      .digest('hex'),
    'hex',
  );
  const signature = req.headers['x-signature'];
  const providedSignature =
    typeof signature === 'string' && /^[0-9a-f]+$/.test(signature)
      ? Buffer.from(signature, 'hex')
      : Buffer.alloc(0);

  if (
    expectedSignature.length !== providedSignature.length ||
    !crypto.timingSafeEqual(expectedSignature, providedSignature)
  ) {
    res.status(401).json({ error: 'invalid_signature' });
    return;
  }

  if (!isValidWebhookEvent(req.body)) {
    res.status(400).json({ error: 'invalid_body' });
    return;
  }

  if (acceptedEventIds.has(req.body.id)) {
    res.status(409).json({ error: 'duplicate_event', id: req.body.id });
    return;
  }

  acceptedEventIds.add(req.body.id);
  res.json({ accepted: true, id: req.body.id });
});

if (require.main === module) {
  const port = Number(process.env.PORT) || 3000;
  app.listen(port, () => {
    console.log(`harbor-tools server listening on :${port}`);
  });
}

module.exports = { app };

