const { test } = require('node:test');
const assert = require('node:assert');
const crypto = require('node:crypto');
const fs = require('node:fs');
const http = require('node:http');
const path = require('node:path');
const { app } = require('../server');

const webhookSecret = fs
  .readFileSync(path.join(__dirname, '../data/webhook-secret.txt'), 'utf8')
  .replace(/\r?\n$/, '');

function startServer() {
  return new Promise((resolve) => {
    const server = http.createServer(app);
    server.listen(0, () => resolve(server));
  });
}

function get(server, path) {
  return new Promise((resolve, reject) => {
    const { port } = server.address();
    http
      .get(`http://127.0.0.1:${port}${path}`, (res) => {
        let body = '';
        res.on('data', (chunk) => (body += chunk));
        res.on('end', () => resolve({ status: res.statusCode, body: JSON.parse(body) }));
      })
      .on('error', reject);
  });
}

function post(server, path, body, headers = {}) {
  return new Promise((resolve, reject) => {
    const { port } = server.address();
    const request = http.request(
      `http://127.0.0.1:${port}${path}`,
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Content-Length': Buffer.byteLength(body),
          ...headers,
        },
      },
      (res) => {
        let responseBody = '';
        res.on('data', (chunk) => (responseBody += chunk));
        res.on('end', () =>
          resolve({ status: res.statusCode, body: JSON.parse(responseBody) }),
        );
      },
    );
    request.on('error', reject);
    request.end(body);
  });
}

function webhookSignature(body) {
  return crypto.createHmac('sha256', webhookSecret).update(body).digest('hex');
}

test('GET /health returns ok', async () => {
  const server = await startServer();
  try {
    const { status, body } = await get(server, '/health');
    assert.strictEqual(status, 200);
    assert.deepStrictEqual(body, { status: 'ok' });
  } finally {
    server.close();
  }
});

test('GET /items returns list', async () => {
  const server = await startServer();
  try {
    const { status, body } = await get(server, '/items');
    assert.strictEqual(status, 200);
    assert.ok(Array.isArray(body.items));
    assert.ok(body.items.length >= 2);
  } finally {
    server.close();
  }
});

test('GET /items/:id returns 404 for missing', async () => {
  const server = await startServer();
  try {
    const { status, body } = await get(server, '/items/99999');
    assert.strictEqual(status, 404);
    assert.strictEqual(body.error, 'not_found');
  } finally {
    server.close();
  }
});

test('POST /webhook accepts a signed event', async () => {
  const server = await startServer();
  const body =
    '{\n  "type": "created",\n  "id": "evt_happy_1",\n  "timestamp": 1721666490,\n  "data": { "source": "provider" }\n}';
  try {
    const response = await post(server, '/webhook', body, {
      'X-Signature': webhookSignature(body),
    });
    assert.strictEqual(response.status, 200);
    assert.deepStrictEqual(response.body, { accepted: true, id: 'evt_happy_1' });
  } finally {
    server.close();
  }
});

test('POST /webhook rejects a replayed event id', async () => {
  const server = await startServer();
  const body = JSON.stringify({
    id: 'evt_replay_1',
    type: 'created',
    timestamp: 1721666491,
    data: { source: 'provider' },
  });
  const headers = { 'X-Signature': webhookSignature(body) };
  try {
    const firstResponse = await post(server, '/webhook', body, headers);
    const replayResponse = await post(server, '/webhook', body, headers);
    assert.strictEqual(firstResponse.status, 200);
    assert.strictEqual(replayResponse.status, 409);
    assert.deepStrictEqual(replayResponse.body, {
      error: 'duplicate_event',
      id: 'evt_replay_1',
    });
  } finally {
    server.close();
  }
});

test('POST /webhook rejects a tampered body with its original signature', async () => {
  const server = await startServer();
  const originalBody = JSON.stringify({
    id: 'evt_tamper_1',
    type: 'created',
    timestamp: 1721666492,
    data: { source: 'provider' },
  });
  const tamperedBody = originalBody.replace('created', 'deleted');
  try {
    const response = await post(server, '/webhook', tamperedBody, {
      'X-Signature': webhookSignature(originalBody),
    });
    assert.strictEqual(response.status, 401);
    assert.deepStrictEqual(response.body, { error: 'invalid_signature' });
  } finally {
    server.close();
  }
});

